export default function (time, noColon, keepMinutes) {
  const splitTime = time.split(":");

  if (!time.includes("AM") && !time.includes("PM")) {
    let [hours, minutes] = splitTime;
    let symbol;

    if (+hours > 0 && +hours < 12) symbol = "AM";
    else if (+hours === 0) {
      hours = "12";
      symbol = "AM";
    } else if (+hours === 12) symbol = "PM";
    else {
      symbol = "PM";
      hours = (+hours - 12).toString();
    }

    if (hours[0] === "0") hours = hours.slice(1);

    if (keepMinutes) {
      if (noColon) return `${hours} ${symbol}`;
      return `${hours}:${minutes} ${symbol}`;
    } else {
      if (noColon) return `${hours} ${symbol}`;
      return `${hours}:00 ${symbol}`;
    }
  } else {
    let [hours] = splitTime;

    if (time.includes("AM")) {
      if (hours === "12") return "00:00:00";

      hours = hours.padStart(2, "0");

      return `${hours}:00:00`;
    } else {
      if (hours === "12") return "12:00:00";
      hours = (Number(hours) + 12).toString();

      return `${hours}:00:00`;
    }
  }
}
